#include <iostream>

int main() {
    int a, b;
    std::cin >> a >> b;

    const int cb = b;

    auto& ra = a;
    ra = ra * 2;

    auto copy = cb;
    copy = copy + 10;

    std::cout << a << '\n';
    std::cout << copy << '\n';
    std::cout << cb << '\n';

    return 0;
}

