solution_code:
#include <iostream>

int& largerRef(int& x, int& y) {
    if (x >= y) return x;
    return y;
}

int main() {
    int a, b;
    std::cin >> a >> b;

    auto& big = largerRef(a, b);
    big += 1;

    std::cout << big << '\n';
    std::cout << a << '\n';
    std::cout << b << '\n';

    return 0;
}
